import React from "react";
import { useNavigate } from "react-router-dom";
import { FaUserCircle, FaSignOutAlt } from "react-icons/fa";
import logo from "../assets/logo.png";
 // ✅ Adjust filename if different

const Layout = ({ children, pageTitle }) => {
  const navigate = useNavigate();
  const userRole = localStorage.getItem("role");

  const handleLogout = () => {
    localStorage.removeItem("role");
    navigate("/");
  };

  const formattedRole =
    userRole?.charAt(0).toUpperCase() + userRole?.slice(1);

  return (
    <div style={{ minHeight: "100vh", background: "#f4f6f9" }}>
      
      {/* HEADER */}
      <header
        style={{
          background: "linear-gradient(90deg, #8b0000, #5c0000)",
          padding: "14px 40px",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          color: "#fff",
          boxShadow: "0 4px 15px rgba(0,0,0,0.08)",
        }}
      >
        {/* Left */}
        <div style={{ display: "flex", alignItems: "center", gap: "15px" }}>
          <img
            src={logo}   // ✅ Using local asset
            alt="University Logo"
            style={{
              height: "40px",
              background: "#fff",
              padding: "4px",
              borderRadius: "6px",
            }}
          />
          <h2 style={{ margin: 0, fontWeight: 600 }}>
            {pageTitle}
          </h2>
        </div>

        {/* Right */}
        {userRole && (
          <div style={{ display: "flex", alignItems: "center", gap: "20px" }}>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "8px",
                background: "rgba(255,255,255,0.15)",
                padding: "6px 14px",
                borderRadius: "20px",
              }}
            >
              <FaUserCircle />
              {formattedRole}
            </div>

            <button
              onClick={handleLogout}
              style={{
                display: "flex",
                alignItems: "center",
                gap: "6px",
                background: "#fff",
                color: "#8b0000",
                border: "none",
                padding: "8px 18px",
                borderRadius: "25px",
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              <FaSignOutAlt />
              Logout
            </button>
          </div>
        )}
      </header>

      {/* BODY */}
      <div style={{ display: "flex" }}>
        
        {/* SIDEBAR */}
        <aside
          style={{
            width: "240px",
            background: "#1e1e2f",
            color: "#fff",
            minHeight: "calc(100vh - 70px)",
            padding: "30px 20px",
          }}
        >
          <h5 style={{ marginBottom: "25px", opacity: 0.7 }}>
            {formattedRole}
          </h5>

          <div style={{ display: "flex", flexDirection: "column", gap: "15px" }}>
            <button className="btn btn-primary">Dashboard</button>
            <button className="btn btn-dark">My Courses</button>
            <button className="btn btn-dark">Assignments</button>
            <button className="btn btn-dark">Students</button>
          </div>
        </aside>

        {/* MAIN CONTENT */}
        <main
          style={{
            flex: 1,
            padding: "40px",
          }}
        >
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;
